    /// Create a provider that talks to a local mock server instead of the real
    /// Copilot API, and doesn't need stored OAuth tokens.
    fn mock_provider(base_url: &str, model: &str) -> MockCopilotProvider {
        MockCopilotProvider {
            model: model.to_string(),
