    // ── Responses API tests ─────────────────────────────────────────────────

    #[test]
    fn needs_responses_api_gpt54() {
        assert!(needs_responses_api("gpt-5.4"));
        assert!(needs_responses_api("gpt-5.4-pro"));
        assert!(needs_responses_api("GPT-5.4")); // case-insensitive
