    ("gpt-4.1", "GPT-4.1 (Copilot)"),
    ("gpt-4.1-mini", "GPT-4.1 Mini (Copilot)"),
    ("gpt-4.1-nano", "GPT-4.1 Nano (Copilot)"),
    ("gpt-5.4", "GPT-5.4 (Copilot)"),
    ("gpt-5.4-pro", "GPT-5.4 Pro (Copilot)"),
    ("gpt-5.2-pro", "GPT-5.2 Pro (Copilot)"),
    ("o1", "o1 (Copilot)"),
