515→/// Send a streaming chat completion request and collect the SSE events into a
516→/// single [`CompletionResponse`].  Used for enterprise proxy endpoints that
517→/// reject non-streaming requests.
518→async fn collect_streamed_completion(
519→    client: &reqwest::Client,
520→    auth: &CopilotAuth,
521→    model: &str,
522→    messages: &[ChatMessage],
523→    tools: &[serde_json::Value],
524→) -> anyhow::Result<CompletionResponse> {
525→    let openai_messages: Vec<serde_json::Value> =
526→        messages.iter().map(ChatMessage::to_openai_value).collect();
527→    let mut body = serde_json::json!({
528→        "model": model,
529→        "messages": openai_messages,
530→        "stream": true,
531→        "stream_options": { "include_usage": true },
532→    });
533→
534→    if !tools.is_empty() {
535→        body["tools"] = serde_json::Value::Array(to_openai_tools(tools));
536→    }
537→
538→    debug!(
539→        model = %model,
540→        messages_count = messages.len(),
541→        tools_count = tools.len(),
542→        "github-copilot enterprise complete (streaming) request"
543→    );
544→    trace!(body = %serde_json::to_string(&body).unwrap_or_default(), "github-copilot enterprise request body");
545→
546→    let http_resp = client
547→        .post(format!("{}/chat/completions", auth.base_url))
548→        .header("Authorization", format!("Bearer {}", auth.token.expose_secret()))
549→        .header("content-type", "application/json")
550→        .header("Editor-Version", EDITOR_VERSION)
551→        .header("User-Agent", COPILOT_USER_AGENT)
552→        .json(&body)
553→        .send()
554→        .await?;
555→
556→    let status = http_resp.status();
557→    if !status.is_success() {
558→        let retry_after_ms = super::retry_after_ms_from_headers(http_resp.headers());
559→        let body_text = http_resp.text().await.unwrap_or_default();
560→        warn!(status = %status, body = %body_text, "github-copilot enterprise API error");
561→        anyhow::bail!(
562→            "{}",
563→            super::with_retry_after_marker(
564→                format!("GitHub Copilot API error HTTP {status}: {body_text}"),
565→                retry_after_ms,
566→            )
567→        );
568→    }
569→
570→    // Parse the SSE stream into events, then assemble a CompletionResponse.
571→    let mut byte_stream = http_resp.bytes_stream();
572→    let mut buf = String::new();
573→    let mut state = StreamingToolState::default();
574→    let mut events: Vec<StreamEvent> = Vec::new();
575→
576→    while let Some(chunk) = byte_stream.next().await {
577→        let chunk = chunk?;
578→        buf.push_str(&String::from_utf8_lossy(&chunk));
579→
580→        while let Some(pos) = buf.find('\n') {
581→            let line = buf[..pos].trim().to_string();
582→            buf = buf[pos + 1..].to_string();
583→
584→            if line.is_empty() {
585→                continue;
586→            }
587→            let Some(data) = line
588→                .strip_prefix("data: ")
589→                .or_else(|| line.strip_prefix("data:"))
590→            else {
591→                continue;
592→            };
593→
594→            match process_openai_sse_line(data, &mut state) {
595→                SseLineResult::Done => {
596→                    events.extend(finalize_stream(&mut state));
597→                    return Ok(stream_events_to_completion(events));
598→                },
599→                SseLineResult::Events(evts) => events.extend(evts),
600→                SseLineResult::Skip => {},
601→            }
602→        }
603→    }
604→
605→    // Process any trailing data in the buffer.
606→    let line = buf.trim().to_string();
607→    if !line.is_empty() {
608→        if let Some(data) = line
609→            .strip_prefix("data: ")
610→            .or_else(|| line.strip_prefix("data:"))
611→        {
612→            match process_openai_sse_line(data, &mut state) {
613→                SseLineResult::Done => {
614→                    events.extend(finalize_stream(&mut state));
615→                    return Ok(stream_events_to_completion(events));
616→                },
617→                SseLineResult::Events(evts) => events.extend(evts),
618→                SseLineResult::Skip => {},
619→            }
620→        }
621→    }
622→    events.extend(finalize_stream(&mut state));
623→    Ok(stream_events_to_completion(events))
624→}
