626→/// Collapse a collected list of [`StreamEvent`]s into a [`CompletionResponse`].
627→fn stream_events_to_completion(events: Vec<StreamEvent>) -> CompletionResponse {
628→    let mut text_parts: Vec<String> = Vec::new();
629→    let mut tool_calls: Vec<ToolCall> = Vec::new();
630→    let mut usage = Usage::default();
631→
632→    // Track in-progress tool calls by index.
633→    let mut pending_tools: Vec<(String, String, String)> = Vec::new(); // (id, name, args)
634→
635→    for event in events {
636→        match event {
637→            StreamEvent::Delta(s) => text_parts.push(s),
638→            StreamEvent::ToolCallStart { id, name, index } => {
639→                while pending_tools.len() <= index {
640→                    pending_tools.push((String::new(), String::new(), String::new()));
641→                }
642→                pending_tools[index].0 = id;
643→                pending_tools[index].1 = name;
644→            },
645→            StreamEvent::ToolCallArgumentsDelta { index, delta } => {
646→                if let Some(entry) = pending_tools.get_mut(index) {
647→                    entry.2.push_str(&delta);
648→                }
649→            },
650→            StreamEvent::ToolCallComplete { index } => {
651→                if let Some(entry) = pending_tools.get(index) {
652→                    let arguments: serde_json::Value =
653→                        serde_json::from_str(&entry.2).unwrap_or_default();
654→                    tool_calls.push(ToolCall {
655→                        id: entry.0.clone(),
656→                        name: entry.1.clone(),
657→                        arguments,
658→                    });
659→                }
660→            },
661→            StreamEvent::Done(u) => usage = u,
662→            StreamEvent::Error(_)
663→            | StreamEvent::ProviderRaw(_)
664→            | StreamEvent::ReasoningDelta(_) => {},
665→        }
666→    }
667→
668→    let text = if text_parts.is_empty() {
669→        None
670→    } else {
671→        Some(text_parts.join(""))
672→    };
673→
674→    CompletionResponse {
675→        text,
676→        tool_calls,
677→        usage,
678→    }
679→}
