218→/// Build a [`CopilotAuth`] from an `account_id` value that may contain a
219→/// proxy-ep hostname persisted from a previous token exchange.
220→fn copilot_auth_from_parts(token: Secret<String>, proxy_ep: Option<&str>) -> CopilotAuth {
221→    match proxy_ep.filter(|s| !s.is_empty()) {
222→        Some(ep) => {
223→            let ep = ep.trim();
224→            // Reject anything that isn't a plain hostname to prevent SSRF via
225→            // crafted proxy-ep values (e.g. internal IPs, @-redirects).
226→            if !ep
227→                .chars()
228→                .all(|c| c.is_ascii_alphanumeric() || matches!(c, '.' | '-'))
229→            {
230→                warn!(proxy_ep = %ep, "ignoring malformed proxy-ep, falling back to individual endpoint");
231→                return CopilotAuth {
232→                    token,
233→                    base_url: COPILOT_API_BASE.to_string(),
234→                    is_enterprise: false,
235→                };
236→            }
237→            // Reject bare IP addresses (v4/v6) to prevent SSRF against cloud
238→            // metadata services, loopback, and RFC-1918 ranges.
239→            if ep.parse::<std::net::IpAddr>().is_ok() {
240→                warn!(proxy_ep = %ep, "ignoring IP-address proxy-ep, falling back to individual endpoint");
241→                return CopilotAuth {
242→                    token,
243→                    base_url: COPILOT_API_BASE.to_string(),
244→                    is_enterprise: false,
245→                };
246→            }
247→            debug!(proxy_ep = %ep, "using enterprise proxy endpoint");
248→            CopilotAuth {
249→                token,
250→                base_url: format!("https://{ep}"),
251→                is_enterprise: true,
252→            }
253→        },
254→        None => CopilotAuth {
255→            token,
256→            base_url: COPILOT_API_BASE.to_string(),
257→            is_enterprise: false,
258→        },
259→    }
260→}
