        assert_eq!(body["model"], "gpt-5.4");
        assert!(body.get("input").is_some());
    }

    #[tokio::test]
    async fn complete_responses_with_tools() {
        let responses_body = serde_json::json!({
            "output": [{
                "type": "function_call",
                "call_id": "call_resp_1",
                "name": "read_file",
                "arguments": "{\"path\":\"/tmp/test.txt\"}"
            }],
            "usage": {"input_tokens": 30, "output_tokens": 15}
