    #[test]
    fn copilot_models_include_gpt54() {
        let ids: Vec<&str> = COPILOT_MODELS.iter().map(|(id, _)| *id).collect();
        assert!(ids.contains(&"gpt-5.4"), "missing gpt-5.4");
